// n8n Code node
// Email Cleanup

const input = $json;

// -----------------------------
// Email basics
// -----------------------------
const emailId = input.id || null;

const html =
  input.body?.content ||
  $input.first().json.body?.content ||
  "";

// Pull clinic/customer/pharmacy from first recipient.
// Example:
// perth.pharmacy+151-EAD.KCP@ashleyandmartin.com.au
//
// clinic       = PERTH
// customerCode = 151-EAD
// pharmacy     = KCP

const recipientEmailAddress =
  input.toRecipients?.[0]?.emailAddress?.address ||
  $input.first().json.toRecipients?.[0]?.emailAddress?.address ||
  "";

const recipientEmailName =
  input.toRecipients?.[0]?.emailAddress?.name ||
  $input.first().json.toRecipients?.[0]?.emailAddress?.name ||
  "";

const toAddress = recipientEmailAddress || recipientEmailName || "";

const clinic = toAddress
  ? toAddress.split(".")[0].trim().toUpperCase()
  : null;

let customerCode = null;
let pharmacy = null;

const recipientMatch = toAddress.match(/\+([^\.@]+)\.([^@]+)@/i);

if (recipientMatch) {
  customerCode = recipientMatch[1]?.trim() || null;
  pharmacy = recipientMatch[2]?.trim().toUpperCase() || null;
}

// -----------------------------
// Helpers
// -----------------------------
function decodeHtml(value) {
  return String(value || "")
    .replace(/&nbsp;/gi, " ")
    .replace(/&amp;/gi, "&")
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/&lt;/gi, "<")
    .replace(/&gt;/gi, ">");
}

function htmlToText(value) {
  return decodeHtml(value)
    .replace(/<style[\s\S]*?<\/style>/gi, " ")
    .replace(/<script[\s\S]*?<\/script>/gi, " ")
    .replace(/<[^>]+>/g, " ")
    .replace(/[\u200B-\u200D\uFEFF\u200A\u202F]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function safeDecodeUrl(value) {
  try {
    return decodeURIComponent(value);
  } catch (error) {
    return value;
  }
}

function extractScriptUrl(value) {
  const raw = String(value || "");

  // Direct clean Ausscripts URL
  let match = raw.match(/https:\/\/ausscripts\.erx\.com\.au\/scripts\/[A-Z0-9]+/i);
  if (match) return match[0];

  // Proofpoint URLDefense wrapped URL
  const proofpointMatch = raw.match(/https:\/\/urldefense\.com\/v3\/__([^;]+)__/i);
  if (proofpointMatch) {
    const innerUrl = safeDecodeUrl(proofpointMatch[1]);

    match = innerUrl.match(/https:\/\/ausscripts\.erx\.com\.au\/scripts\/[A-Z0-9]+/i);
    if (match) return match[0];
  }

  // Fallback after HTML entity decode
  const decodedHtml = decodeHtml(raw);
  match = decodedHtml.match(/https:\/\/ausscripts\.erx\.com\.au\/scripts\/[A-Z0-9]+/i);
  if (match) return match[0];

  return null;
}

// -----------------------------
// Extract script details
// -----------------------------
const text = htmlToText(html);
const scriptUrl = extractScriptUrl(html);
const scriptId = scriptUrl ? scriptUrl.split("/").pop() : null;

// Example text:
// Tap the link to view BV's ePrescription for 5% Minoxidil + 0.25% Finasteride Lotion lotion ...
const prescriptionMatch = text.match(
  /Tap the link to view\s+(.+?)'s ePrescription for\s+(.+?)(?:\s+https:\/\/ausscripts\.erx\.com\.au\/scripts\/| Have a question|$)/i
);

const patientInitials = prescriptionMatch?.[1]?.trim() || null;

let productName = prescriptionMatch?.[2]?.trim() || null;

if (productName) {
  productName = productName
    .replace(/\s+/g, " ")
    .replace(/\s+lotion\s+/i, " Lotion ")
    .replace(/(Lotion)\s+\1/gi, "$1")
    .trim();

  // Fix duplicated product format from this email template
  const words = productName.split(" ");
  const midpoint = Math.floor(words.length / 2);

  const firstHalf = words.slice(0, midpoint).join(" ").trim();
  const secondHalf = words.slice(midpoint).join(" ").trim();

  if (
    firstHalf &&
    secondHalf &&
    firstHalf.toLowerCase() === secondHalf.toLowerCase()
  ) {
    productName = firstHalf;
  }

  // Specific cleanup for duplicated "Lotion product again" style
  const duplicateProductMatch = productName.match(/^(.+?Lotion)\s+\1$/i);
  if (duplicateProductMatch) {
    productName = duplicateProductMatch[1];
  }
}

// -----------------------------
// Date and folder names
// -----------------------------
const receivedDate = input.receivedDateTime
  ? new Date(input.receivedDateTime).toISOString().slice(0, 10)
  : new Date().toISOString().slice(0, 10);

const dateFolderName = receivedDate;
const clinicFolderName = clinic || "UNKNOWNCLINIC";

const safePatientInitials = patientInitials || "UnknownInitials";
const safeScriptId = scriptId || "UnknownScript";
const fileName = `${receivedDate}-${safeScriptId}-${safePatientInitials}.pdf`;

// -----------------------------
// SharePoint / Graph IDs
// -----------------------------
const DriveID = "b!keZy0EVJt0ydRozgmmR1eQMBvSWtB5hGktxakZsBcZvoqANme--qSo6QvDZ3hdgU";

const AUMedOrderID = "01Y4DA4OPCXITTGW45PJHZBMOQ2WVAPCD2";

const CompletedOrdersID = "01Y4DA4OMCIC7MC3JRSBG2QB4JYEGHALNK";

// Correct folder ID for:
// -=AU Med Orders=- / OrderInProgress
const OrderInProgressID = "01Y4DA4OMQFXPAO6YE25F2FTI3HY3VF4HL";

// -----------------------------
// Final output
// -----------------------------
return {
  json: {
    isPrescriptionEmail: !!scriptUrl,

    emailId,
    originalMessageId: emailId,

    toAddress,

    clinic,
    clinicFolderName,

    customerCode,
    pharmacy,

    patientInitials,
    productName,

    scriptUrl,
    scriptId,

    receivedDate,
    dateFolderName,

    fileName,

    DriveID,
    AUMedOrderID,
    CompletedOrdersID,
    OrderInProgressID,
  },
};

